var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 그 노바급 리액터라는 걸 샬롯이 훔쳐갔다는 거야?","JPN":"つまり……そのノヴァ級リアクターってものをシャーロットが盗んだってこと？","ENG":"So... Carlota stole the Nova-Class Reactor?","TWN":"意思就是……夏洛特把那個叫諾瓦反應爐的東西搶走了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 어디에 쓸지는 몰라도 그렇게 좋은 목적은 아니겠지.","JPN":"そうだ。何に使うつもりかわからないが、きっといい目的ではないだろう。","ENG":"Yes. We don’t know why, but I don’t think she will put it to good use.","TWN":"沒錯，雖然不知道用途為何，但肯定不是什麼好事！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러고 보니 아가씨의 피도 추출해 갔다고?","JPN":"そういえば、嬢ちゃんの血も抜いて行ったらしいな？","ENG":"And Carlota took your blood as well?","TWN":"而且她還抽你的血？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 뭔가 보석처럼 가공해서 가져갔어.","JPN":"うん。宝石みたいに加工して持って行ったよ。","ENG":"Yes. She crystallized my blood and took it away.","TWN":"嗯，她把我的血加工成類似寶石的東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 말을 들으니 더 불안해지는군.","JPN":"それを聞いたらますます不安になってきた。","ENG":"Okay, that makes me very nervous.","TWN":"聽你這麼說我又更不安了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 기억하기로 아가씨의 피는 보통 피가 아니었던 것 같은데.","JPN":"俺の記憶が正しければ、嬢ちゃんの血は特別なものだった気がするんだが。","ENG":"If I remember it correctly, your blood is not ordinary, right?","TWN":"我記得，你的血應該不是普通的血吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"맞습니다. 성분이 아주 유니크하죠.","JPN":"そうです。成分がとてもユニークなんですよ。","ENG":"Yes, it’s very unique indeed.","TWN":"是的，成分非常特殊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나, 남의 피 가지고 함부로 떠들지 마! 부끄럽게!","JPN":"ひ、人の血を勝手にユニークだなんて言わないでよ！　恥ずかしいな！","ENG":"S-stop talking about my blood, you’re embarrassing me!","TWN":"不要在那邊討論我的血啦！很害羞欸！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 아저씨, 내가 이걸 물어봐도 될지 모르겠는데……. 저 사람 분명…….","JPN":"ところでおじさん、聞いてもいいのかわからないけど……あの人って……","ENG":"Um, Mr. Mason, I’m not sure if I should be asking you about this... But is she...?","TWN":"大叔，有個問題我不知道該不該問……她是那個……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 리플레이서 퀸이 맞아.","JPN":"ああ、リプレイサー・クイーンだ。","ENG":"Yes, she was the Replacer Queen.","TWN":"沒錯，就是克隆·女皇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금은 제이나 크로펠이라는 델타 세븐 요원이라고 하지만 말이야.","JPN":"今はジェイナ・クロペルという名のデルタセブン要員だけどな。","ENG":"But she is now Jaina Kropel, one of the Delta Seven agents.","TWN":"但是她現在叫作婕娜·克洛佩爾，是第七三角洲部隊的隊員。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 그 퀸이라고? 그 여자가 왜 아저씨랑 같이 다니는 거야?","JPN":"本当にあのクイーンなの？　あの女がどうしておじさんと一緒にいるの？","ENG":"So she really is the Queen? Why is she with you?","TWN":"她真的是那個女皇喔？你們怎麼會一起行動？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 퀸은…… 아저씨네 형의 원수 아니었어?","JPN":"リプレイサー・クイーンは……おじさんのお兄さんの仇じゃなかった？","ENG":"The Replacer Queen... She killed your brother, didn’t she?","TWN":"克隆·女皇……不是害死你哥哥的兇手嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……나도 아직 마음이 정리된 게 아니라 대답하기 어렵군.","JPN":"……俺もまだ気持ちの整理がついていないから、答えにくいな。","ENG":"I can’t really explain, because I’m still confused myself.","TWN":"……我自己也還沒整理好心情，不知道該怎麼回答你。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"확실한 건 리플레이서 사태 때 내 복수는 완성되었다는 거야.","JPN":"確実に言えることは、リプレイサー事件の時に俺の復讐は終わったということだ。","ENG":"But one thing I’m certain of is that I did take revenge for my brother during the Replacer incident.","TWN":"但我能確定的是，克隆集團事件時，我就已經算是報仇了。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저기 있는 제이나 크로펠은……. 일종의 복제인간 같은 거지.","JPN":"あそこにいるジェイナ・クロペルは……一種のクローン人間のようなものさ。","ENG":"That Jaina Kropel is... like a clone.","TWN":"這位婕娜·克洛佩爾……就類似複製人的概念。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나마 기억도, 인격도 퀸과는 한참 동떨어져 있어.","JPN":"記憶も人格も、クイーンとはかなりかけ離れている。","ENG":"All she has is some of the Queen’s memory, and her personality is very different from the original.","TWN":"無論是記憶或是人格特質，都和女皇有天壤之別。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 사람을 상대로 계속 화를 내는 것도……. 조금 바보 같아서 말이지.","JPN":"そんな人を相手に怒り続けるのも……バカバカしくなっちまってな。","ENG":"So... what’s the point of staying mad at someone like her, right?","TWN":"若是硬要把她當成出氣對象……覺得有點愚蠢。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 비숍, 신나래 양과는 반대의 상황이군요.","JPN":"リプレイサー・ビショップ、シンジョウ・ナルミさんとは逆の状態ですね。","ENG":"So, she’s totally opposite of the Replacer Bishop, Shin Narae.","TWN":"和克隆·大主教的情況相反呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조금 아이러니한데요.","JPN":"なんだか皮肉ですね。","ENG":"That’s ironic.","TWN":"有點諷刺。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저……. 말씀 중에 죄송하지만 서둘러야 할 것 같아요.","JPN":"あの……お取込み中にすみませんが、急いだほうがよさそうです。","ENG":"Um... I’m sorry to interrupt, but I think we should hurry.","TWN":"那個……不好意思打斷你們，我們可能需要加快動作。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"퇴각한 목표의 위치를 추적하기가 점점 어려워지고 있어요.","JPN":"退却したターゲットの位置を追跡するのが難しくなってきました。","ENG":"It’s getting harder to track the target's location.","TWN":"逃走目標的位置似乎越來越難追蹤。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 어째서지?","JPN":"えっ？　どうして？","ENG":"What? Why?","TWN":"嗯？怎麼會？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그건 내가 대답해 줄 수 있을 것 같군.","JPN":"それは俺が説明してやるよ。","ENG":"I believe I can answer that question.","TWN":"這個問題就由我來回答吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여긴 내가 햇병아리일 때 비밀 작전을 나왔던 곳이야.","JPN":"ここは俺が新米の時に秘密作戦で来た場所だ。","ENG":"I visited here on a secret operation when I was a rookie.","TWN":"我還是新兵的時候，曾經來過這裡執行秘密作戰。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차원폭풍이 시도 때도 없이 몰아치는 곳이지.","JPN":"次元の暴風がいつも吹き荒れてるんだ。","ENG":"This place is always filled with dimensional storms.","TWN":"這個地方總是次元風暴肆虐。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아마도 폭풍이 점점 강해지고 있는 중일 거야. 그러면 발신기도 소용이 없어.","JPN":"恐らく暴風がますます強まっているせいだろう。\\nこんな状況じゃ発信機もあてにならない。","ENG":"It’s probably the storm getting stronger, interfering with the transmitter signals.","TWN":"現在風暴可能正在逐漸增強當中，所以發射器也派不上用場。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"곤란하게 됐군. 그 아가씨는 대체 왜 이런 곳으로 들어간 거지?","JPN":"困ったな。あのお嬢ちゃんはどうしてこんな場所へ向かったんだ？","ENG":"That’s a problem. Why is the girl going into the storm?","TWN":"真是傷腦筋！那個小丫頭跑到這裡來幹嘛啦！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아마…… 등대를 찾으러 간 거 아닐까?","JPN":"恐らく……灯台を探しに行ったんじゃないかな？","ENG":"That’s probably because... she’s looking for the Lighthouse.","TWN":"她……可能是要去找燈塔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"등대?","JPN":"灯台？","ENG":"The Lighthouse?","TWN":"燈塔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"원래 샬롯이 우리에게 했던 의뢰가 그거였어. 이 곳에 버려진 등대라는 유물을 회수하는 걸 도와 달라고 했거든.","JPN":"元々シャーロットが私たちに依頼したのがそれだったの。\\nここに捨てられた灯台という遺物を回収するのを手伝ってほしいってね。","ENG":"Carlota contacted us and asked us to find the Lighthouse in the first place. She said it was a lost Artifact that she wanted to retrieve.","TWN":"夏洛特來找我們，就是希望我們可以協助她，找到被遺落在這裡的燈塔。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조금 전까지는 우릴 속이기 위한 말이라고 생각했는데…….","JPN":"さっきまでは私たちを騙すための口実かと思っていたけど……","ENG":"I thought she lied to us to lure us in...","TWN":"我剛還以為這只是她要引我們上鉤的說詞……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전투 중에 급히 후퇴한 걸 보면 정말 등대를 찾고 있었던 걸지도 몰라.","JPN":"戦闘中に急に引き下がったのも、本当に灯台を探しているのかもしれない。","ENG":"But maybe she really was looking for the Lighthouse, considering how quickly she retreated during the battle.","TWN":"但是看她在打到一半急忙撤退的樣子，很可能真的是在找燈塔。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"등대라……. 그러고 보니 그런 물건도 있었던 것 같아.","JPN":"灯台か……そういえば、聞いたことがあるな。","ENG":"The Lighthouse... Yes, there was such a thing.","TWN":"燈塔……好像有點印象。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭔가 알고 있나?","JPN":"何か知ってるのか？","ENG":"You know about it?","TWN":"你知道什麼嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"말했듯이 햇병아리 시절의 기억이지.","JPN":"さっき話した新米の頃の記憶さ。","ENG":"Like I told you, I was here when I was a rookie.","TWN":"就跟你說是新兵時候的事！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 그게 버려진 비밀 기지라면 내가 위치를 알아. 늦지 않게 바로 출발하지.","JPN":"とにかく、それが捨てられた秘密基地のことだとしたら、俺が場所を知ってるぜ。\\n今すぐ出発しよう。","ENG":"Anyway, if it means the abandoned facility, I know where it is. Let’s go.","TWN":"總之，如果是指那個荒廢的秘密基地，那我知道地方，趕緊出發吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 나도 여기 있던 조난자들만 대피시키고 바로 따라갈게.","JPN":"うん。私もここにいる遭難者たちを避難させたら向かうね。","ENG":"Okay, I’ll join you after I evacuate the castaways.","TWN":"好，我安置好其他的遇難者後立刻跟上！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조난자? 무슨 말이지?","JPN":"遭難者？　いったい何のことだ？","ENG":"Castaways? What do you mean?","TWN":"遇難者？誰遇難？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 샬롯과 함께 움직이다가 여기서 조난 신호를 받았거든.","JPN":"ああ、シャーロットと一緒に行動している時に、遭難信号を受けたの。","ENG":"Oh, we received a distress signal when we were with Carlota.","TWN":"就我們剛才和夏洛特一起行動時，收到從這裡發出的求救訊號。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조난 신호? 하지만 여긴 아무도 없는데?","JPN":"遭難信号？　でもここには誰もいないぞ？","ENG":"A distress signal? But there’s no one here.","TWN":"求救訊號？連個鬼影也沒看到啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh?","TWN":"奇怪……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아냐. 분명 이상한 의자에 앉아 있던 꼬맹이와 창백한 얼굴의 남자가 있었는데……","JPN":"さっきまでここに変な椅子に座った子どもと、青白い顔の男の人がいたのに……","ENG":"No, I definitely saw a girl on a weird chair and a pale man.","TWN":"可是剛剛明明有一個坐在椅子上的奇怪丫頭，和一個臉色慘白的男生……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배! 선배는 못 봤어?","JPN":"先輩！　先輩は見たよね？","ENG":"Shiyoon, didn’t you see them?","TWN":"前輩！你沒看到嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……글쎄요. 저도 언제 사라졌는지 모르겠네요.","JPN":"……そうですね。僕もいつ消えたのかはわかりませんね。","ENG":"I’m not sure. I didn’t see them leaving.","TWN":"……這個嘛，我也不知道是什麼時候消失的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기척을 감지하는 능력은 꽤 좋다고 자부하는 편인데…… 조금 당황스러운데요.","JPN":"気配を感知する能力には優れていると自負しているので……正直驚いています。","ENG":"I’m pretty good at sensing people... This is a bit confusing.","TWN":"我自認為對周圍的動靜都滿敏銳的……剛才可能有點反應不過來。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 전투 중에 도망친 건가?","JPN":"もしかして、戦闘中に逃げたのかな？","ENG":"Did they run away while we were in a battle?","TWN":"是在我們戰鬥途中跑掉的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그럴 사람들 같지는 않았는데……?","JPN":"でも、そんな人たちとは思えなかったけど……？","ENG":"They didn’t seem like the type who’d just run away though.","TWN":"但感覺他們又不像是會跑掉的人……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};